import React, { useEffect, useState } from 'react';
import { BrowserRouter, Routes, Route, Link } from 'react-router-dom';
import ProductsList from './components/ProductsList';
import ProductForm from './components/ProductForm';

function App() {
  const [isAuth, setIsAuth] = useState(null);

  useEffect(() => {
    fetch('http://localhost:5000/api/task3/me', { credentials: 'include' })
      .then(res => {
        if (!res.ok) throw new Error();
        return res.json();
      })
      .then(() => setIsAuth(true))
      .catch(() => setIsAuth(false));
  }, []);

  if (isAuth === null) return <h2>Checking authentication...</h2>;
  if (!isAuth) {
    window.location.href = 'http://localhost:3001';
    return null;
  }

  return (
    <BrowserRouter>
      <div className="app-layout">
        <header className="top-nav">
          <Link to="/" className="brand">Intern Spark Store</Link>
          <Link to="/create" className="btn btn-primary">Add Product</Link>
          <button onClick={async () => {
            await fetch('http://localhost:5000/api/task3/logout', { method: 'POST', credentials: 'include' });
            window.location.href = 'http://localhost:3001/login';
          }}>Logout</button>
        </header>
        <main className="container">
          <Routes>
            <Route path="/" element={<ProductsList />} />
            <Route path="/create" element={<ProductForm />} />
            <Route path="/edit/:id" element={<ProductForm />} />
          </Routes>
        </main>
      </div>
    </BrowserRouter>
  );
}

export default App;
